-- ========== 20260624120000_quote_free_text ==========
-- Orâ”œÂºamento em texto livre com valor fechado (sem itens no estoque) ALTER TABLE "quotes" ADD COLUMN "free_text_enabled" BOOLEAN NOT NULL DEFAULT false; ALTER TABLE "quotes" ADD COLUMN "free_text_content" TEXT; ALTER TABLE "quotes" ADD COLUMN "free_text_amount" DECIMAL(12,2);

-- ========== 20260625120000_dashboard_cache ==========
-- Dashboard cache (sincronizado com supabase/migrations/20260625120000_dashboard_cache.sql) CREATE TABLE IF NOT EXISTS dashboard_cache (   id TEXT PRIMARY KEY,   organization_id TEXT NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,   date DATE NOT NULL,   revenue DECIMAL(14, 2) NOT NULL DEFAULT 0,   expenses DECIMAL(14, 2) NOT NULL DEFAULT 0,   profit DECIMAL(14, 2) NOT NULL DEFAULT 0,   ticket_average DECIMAL(14, 2) NOT NULL DEFAULT 0,   service_orders INTEGER NOT NULL DEFAULT 0,   closed_orders INTEGER NOT NULL DEFAULT 0,   computed_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),   UNIQUE (organization_id, date) );  CREATE INDEX IF NOT EXISTS dashboard_cache_org_date_idx ON dashboard_cache (organization_id, date);

-- ========== 20260703140000_service_order_closed_at ==========
-- Data de fechamento estâ”œÃ­vel da OS: reconhecimento de lucro por competâ”œÂ¬ncia, -- independente de ediâ”œÂºâ”œÃes futuras (antes usâ”œÃ­vamos updated_at, que se movia). ALTER TABLE "service_orders" ADD COLUMN "closed_at" TIMESTAMP(3);  -- Backfill: primeira vez em que a OS entrou em um status reconhecido (histâ”œâ”‚rico). UPDATE "service_orders" so SET "closed_at" = sub.first_closed FROM (   SELECT "service_order_id", MIN("created_at") AS first_closed   FROM "service_order_status_history"   WHERE "to_status" IN ('FINISHED', 'DELIVERED', 'AWAITING_PAYMENT')   GROUP BY "service_order_id" ) sub WHERE so."id" = sub."service_order_id";  -- Fallback: OS jâ”œÃ­ reconhecidas sem histâ”œâ”‚rico usam a â”œâ•‘ltima atualizaâ”œÂºâ”œÃºo. UPDATE "service_orders" SET "closed_at" = "updated_at" WHERE "closed_at" IS NULL   AND "status" IN ('FINISHED', 'DELIVERED', 'AWAITING_PAYMENT');

-- ========== 20260703160000_fixed_expenses ==========
-- Despesas fixas: modelos reutilizâ”œÃ­veis (nome + valor + cor) para gerar -- lanâ”œÂºamentos de contas a pagar recorrentes de forma padronizada. CREATE TABLE "fixed_expenses" (     "id" TEXT NOT NULL,     "organization_id" TEXT NOT NULL,     "name" TEXT NOT NULL,     "amount" DECIMAL(12,2) NOT NULL,     "color" TEXT NOT NULL DEFAULT '#DC2626',     "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "updated_at" TIMESTAMP(3) NOT NULL,      CONSTRAINT "fixed_expenses_pkey" PRIMARY KEY ("id") );  CREATE INDEX "fixed_expenses_organization_id_idx" ON "fixed_expenses"("organization_id");  ALTER TABLE "fixed_expenses" ADD CONSTRAINT "fixed_expenses_organization_id_fkey" FOREIGN KEY ("organization_id") REFERENCES "organizations"("id") ON DELETE CASCADE ON UPDATE CASCADE;

-- ========== 20260703180000_outsourced_services ==========
-- Serviâ”œÂºos terceirizados: catâ”œÃ­logo de serviâ”œÂºos feitos por terceiros -- (alinhamento, balanceamento, retâ”œÂ¡fica, etc.) com custo e preâ”œÂºo de venda. CREATE TABLE "outsourced_services" (     "id" TEXT NOT NULL,     "organization_id" TEXT NOT NULL,     "name" TEXT NOT NULL,     "provider" TEXT,     "category" TEXT,     "cost_price" DECIMAL(12,2) NOT NULL DEFAULT 0,     "sale_price" DECIMAL(12,2) NOT NULL DEFAULT 0,     "is_active" BOOLEAN NOT NULL DEFAULT true,     "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "updated_at" TIMESTAMP(3) NOT NULL,      CONSTRAINT "outsourced_services_pkey" PRIMARY KEY ("id") );  CREATE INDEX "outsourced_services_organization_id_is_active_idx" ON "outsourced_services"("organization_id", "is_active");  ALTER TABLE "outsourced_services" ADD CONSTRAINT "outsourced_services_organization_id_fkey" FOREIGN KEY ("organization_id") REFERENCES "organizations"("id") ON DELETE CASCADE ON UPDATE CASCADE;  -- Vâ”œÂ¡nculo opcional do item da OS com o serviâ”œÂºo terceirizado do catâ”œÃ­logo. ALTER TABLE "service_order_items" ADD COLUMN "outsourced_service_id" TEXT;  ALTER TABLE "service_order_items" ADD CONSTRAINT "service_order_items_outsourced_service_id_fkey" FOREIGN KEY ("outsourced_service_id") REFERENCES "outsourced_services"("id") ON DELETE SET NULL ON UPDATE CASCADE;

