 DEFAULT 'CAIXA',     "bank" TEXT,     "agency" TEXT,     "account_number" TEXT,     "holder" TEXT,     "opening_balance" DECIMAL(14,2) NOT NULL DEFAULT 0,     "current_balance" DECIMAL(14,2) NOT NULL DEFAULT 0,     "status" "FinancialAccountStatus" NOT NULL DEFAULT 'ACTIVE',     "color" TEXT NOT NULL DEFAULT '#0E7490',     "icon" TEXT,     "allows_movement" BOOLEAN NOT NULL DEFAULT true,     "is_primary" BOOLEAN NOT NULL DEFAULT false,     "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "updated_at" TIMESTAMP(3) NOT NULL,     CONSTRAINT "financial_accounts_pkey" PRIMARY KEY ("id") );  CREATE INDEX "financial_accounts_organization_id_status_idx" ON "financial_accounts"("organization_id", "status");  ALTER TABLE "financial_accounts" ADD CONSTRAINT "financial_accounts_organization_id_fkey"     FOREIGN KEY ("organization_id") REFERENCES "organizations"("id") ON DELETE CASCADE ON UPDATE CASCADE;  -- cost_centers CREATE TABLE "cost_centers" (     "id" TEXT NOT NULL,     "organization_id" TEXT NOT NULL,     "name" TEXT NOT NULL,     "is_system" BOOLEAN NOT NULL DEFAULT false,     "is_active" BOOLEAN NOT NULL DEFAULT true,     "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     CONSTRAINT "cost_centers_pkey" PRIMARY KEY ("id") );  CREATE UNIQUE INDEX "cost_centers_organization_id_name_key" ON "cost_centers"("organization_id", "name"); CREATE INDEX "cost_centers_organization_id_idx" ON "cost_centers"("organization_id");  ALTER TABLE "cost_centers" ADD CONSTRAINT "cost_centers_organization_id_fkey"     FOREIGN KEY ("organization_id") REFERENCES "organizations"("id") ON DELETE CASCADE ON UPDATE CASCADE;  -- financial_transfers CREATE TABLE "financial_transfers" (     "id" TEXT NOT NULL,     "organization_id" TEXT NOT NULL,     "from_account_id" TEXT NOT NULL,     "to_account_id" TEXT NOT NULL,     "amount" DECIMAL(14,2) NOT NULL,     "transfer_date" DATE NOT NULL,     "responsible_user_id" TEXT,     "notes" TEXT,     "attachment_url" TEXT,     "status" "TransferStatus" NOT NULL DEFAULT 'COMPLETED',     "created_by_user_id" TEXT,     "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "updated_at" TIMESTAMP(3) NOT NULL,     CONSTRAINT "financial_transfers_pkey" PRIMARY KEY ("id") );  CREATE INDEX "financial_transfers_organization_id_transfer_date_idx" ON "financial_transfers"("organization_id", "transfer_date");  ALTER TABLE "financial_transfers" ADD CONSTRAINT "financial_transfers_organization_id_fkey"     FOREIGN KEY ("organization_id") REFERENCES "organizations"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "financial_transfers" ADD CONSTRAINT "financial_transfers_from_account_id_fkey"     FOREIGN KEY ("from_account_id") REFERENCES "financial_accounts"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "financial_transfers" ADD CONSTRAINT "financial_transfers_to_account_id_fkey"     FOREIGN KEY ("to_account_id") REFERENCES "financial_accounts"("id") ON DELETE RESTRICT ON UPDATE CASCADE;  -- capital_contributions CREATE TABLE "capital_contributions" (     "id" TEXT NOT NULL,     "organization_id" TEXT NOT NULL,     "partner_name" TEXT NOT NULL,     "from_account_id" TEXT,     "to_account_id" TEXT NOT NULL,     "amount" DECIMAL(14,2) NOT NULL,     "contribution_date" DATE NOT NULL,     "reason" TEXT,     "created_by_user_id" TEXT,     "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     CONSTRAINT "capital_contributions_pkey" PRIMARY KEY ("id") );  CREATE INDEX "capital_contributions_organization_id_contribution_date_idx" ON "capital_contributions"("organization_id", "contribution_date");  ALTER TABLE "capital_contributions" ADD CONSTRAINT "capital_contributions_organization_id_fkey"     FOREIGN KEY ("organization_id") REFERENCES "organizations"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "capital_contributions" ADD CONSTRAINT "capital_contributions_to_account_id_fkey"     FOREIGN KEY ("to_account_id") REFERENCES "financial_accounts"("id") ON DELETE RESTRICT ON UPDATE CASCADE;  -- partner_withdrawals CREATE TABLE "partner_withdrawals" (     "id" TEXT NOT NULL,     "organization_id" TEXT NOT NULL,     "partner_name" TEXT NOT NULL,     "from_account_id" TEXT NOT NULL,     "amount" DECIMAL(14,2) NOT NULL,     "withdrawal_date" DATE NOT NULL,     "withdrawal_type" "PartnerWithdrawalType" NOT NULL,     "reason" TEXT,     "created_by_user_id" TEXT,     "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     CONSTRAINT "partner_withdrawals_pkey" PRIMARY KEY ("id") );  CREATE INDEX "partner_withdrawals_organization_id_withdrawal_date_idx" ON "partner_withdrawals"("organization_id", "withdrawal_date");  ALTER TABLE "partner_withdrawals" ADD CONSTRAINT "partner_withdrawals_organization_id_fkey"     FOREIGN KEY ("organization_id") REFERENCES "organizations"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "partner_withdrawals" ADD CONSTRAINT "partner_withdrawals_from_account_id_fkey"     FOREIGN KEY ("from_account_id") REFERENCES "financial_accounts"("id") ON DELETE RESTRICT ON UPDATE CASCADE;  -- loans CREATE TABLE "loans" (     "id" TEXT NOT NULL,     "organization_id" TEXT NOT NULL,     "bank_name" TEXT NOT NULL,     "contract_number" TEXT,     "principal_amount" DECIMAL(14,2) NOT NULL,     "interest_rate" DECIMAL(5,2),     "installments" INTEGER NOT NULL DEFAULT 1,     "installment_amount" DECIMAL(14,2) NOT NULL,     "first_due_date" DATE NOT NULL,     "destination_account_id" TEXT NOT NULL,     "outstanding_balance" DECIMAL(14,2) NOT NULL,     "status" "LoanStatus" NOT NULL DEFAULT 'ACTIVE',     "received_at" DATE,     "notes" TEXT,     "created_by_user_id" TEXT,     "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     "updated_at" TIMESTAMP(3) NOT NULL,     CONSTRAINT "loans_pkey" PRIMARY KEY ("id") );  CREATE INDEX "loans_organization_id_status_idx" ON "loans"("organization_id", "status");  ALTER TABLE "loans" ADD CONSTRAINT "loans_organization_id_fkey"     FOREIGN KEY ("organization_id") REFERENCES "organizations"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "loans" ADD CONSTRAINT "loans_destination_account_id_fkey"     FOREIGN KEY ("destination_account_id") REFERENCES "financial_accounts"("id") ON DELETE RESTRICT ON UPDATE CASCADE;  -- loan_installments CREATE TABLE "loan_installments" (     "id" TEXT NOT NULL,     "organization_id" TEXT NOT NULL,     "loan_id" TEXT NOT NULL,     "installment_number" INTEGER NOT NULL,     "due_date" DATE NOT NULL,     "amount" DECIMAL(14,2) NOT NULL,     "status" "LoanInstallmentStatus" NOT NULL DEFAULT 'OPEN',     "financial_entry_id" TEXT,     "paid_at" TIMESTAMP(3),     "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     CONSTRAINT "loan_installments_pkey" PRIMARY KEY ("id") );  CREATE UNIQUE INDEX "loan_installments_financial_entry_id_key" ON "loan_installments"("financial_entry_id"); CREATE INDEX "loan_installments_loan_id_idx" ON "loan_installments"("loan_id"); CREATE INDEX "loan_installments_organization_id_due_date_idx" ON "loan_installments"("organization_id", "due_date");  ALTER TABLE "loan_installments" ADD CONSTRAINT "loan_installments_organization_id_fkey"     FOREIGN KEY ("organization_id") REFERENCES "organizations"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "loan_installments" ADD CONSTRAINT "loan_installments_loan_id_fkey"     FOREIGN KEY ("loan_id") REFERENCES "loans"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "loan_installments" ADD CONSTRAINT "loan_installments_financial_entry_id_fkey"     FOREIGN KEY ("financial_entry_id") REFERENCES "financial_entries"("id") ON DELETE SET NULL ON UPDATE CASCADE;  -- financial_account_movements (razâ”œÃºo) CREATE TABLE "financial_account_movements" (     "id" TEXT NOT NULL,     "organization_id" TEXT NOT NULL,     "account_id" TEXT NOT NULL,     "direction" "LedgerDirection" NOT NULL,     "amount" DECIMAL(14,2) NOT NULL,     "balance_after" DECIMAL(14,2) NOT NULL,     "movement_kind" "LedgerMovementKind" NOT NULL,     "movement_date" DATE NOT NULL,     "description" TEXT,     "financial_entry_id" TEXT,     "transfer_id" TEXT,     "contribution_id" TEXT,     "withdrawal_id" TEXT,     "loan_id" TEXT,     "loan_installment_id" TEXT,     "cash_movement_id" TEXT,     "reconciliation_status" "ReconciliationStatus" NOT NULL DEFAULT 'PENDING',     "external_ref" TEXT,     "created_by_user_id" TEXT,     "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     CONSTRAINT "financial_account_movements_pkey" PRIMARY KEY ("id") );  CREATE INDEX "financial_account_movements_organization_id_account_id_movement_date_idx"     ON "financial_account_movements"("organization_id", "account_id", "movement_date"); CREATE INDEX "financial_account_movements_financial_entry_id_idx" ON "financial_account_movements"("financial_entry_id"); CREATE INDEX "financial_account_movements_transfer_id_idx" ON "financial_account_movements"("transfer_id");  ALTER TABLE "financial_account_movements" ADD CONSTRAINT "financial_account_movements_organization_id_fkey"     FOREIGN KEY ("organization_id") REFERENCES "organizations"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "financial_account_movements" ADD CONSTRAINT "financial_account_movements_account_id_fkey"     FOREIGN KEY ("account_id") REFERENCES "financial_accounts"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "financial_account_movements" ADD CONSTRAINT "financial_account_movements_financial_entry_id_fkey"     FOREIGN KEY ("financial_entry_id") REFERENCES "financial_entries"("id") ON DELETE SET NULL ON UPDATE CASCADE; ALTER TABLE "financial_account_movements" ADD CONSTRAINT "financial_account_movements_transfer_id_fkey"     FOREIGN KEY ("transfer_id") REFERENCES "financial_transfers"("id") ON DELETE SET NULL ON UPDATE CASCADE; ALTER TABLE "financial_account_movements" ADD CONSTRAINT "financial_account_movements_contribution_id_fkey"     FOREIGN KEY ("contribution_id") REFERENCES "capital_contributions"("id") ON DELETE SET NULL ON UPDATE CASCADE; ALTER TABLE "financial_account_movements" ADD CONSTRAINT "financial_account_movements_withdrawal_id_fkey"     FOREIGN KEY ("withdrawal_id") REFERENCES "partner_withdrawals"("id") ON DELETE SET NULL ON UPDATE CASCADE; ALTER TABLE "financial_account_movements" ADD CONSTRAINT "financial_account_movements_loan_id_fkey"     FOREIGN KEY ("loan_id") REFERENCES "loans"("id") ON DELETE SET NULL ON UPDATE CASCADE; ALTER TABLE "financial_account_movements" ADD CONSTRAINT "financial_account_movements_loan_installment_id_fkey"     FOREIGN KEY ("loan_installment_id") REFERENCES "loan_installments"("id") ON DELETE SET NULL ON UPDATE CASCADE;  -- bank_reconciliations CREATE TABLE "bank_reconciliations" (     "id" TEXT NOT NULL,     "organization_id" TEXT NOT NULL,     "account_id" TEXT NOT NULL,     "period_start" DATE NOT NULL,     "period_end" DATE NOT NULL,     "bank_balance" DECIMAL(14,2) NOT NULL,     "system_balance" DECIMAL(14,2) NOT NULL,     "difference" DECIMAL(14,2) NOT NULL,     "notes" TEXT,     "reconciled_at" TIMESTAMP(3),     "created_by_user_id" TEXT,     "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,     CONSTRAINT "bank_reconciliations_pkey" PRIMARY KEY ("id") );  CREATE INDEX "bank_reconciliations_organization_id_account_id_idx" ON "bank_reconciliations"("organization_id", "account_id");  ALTER TABLE "bank_reconciliations" ADD CONSTRAINT "bank_reconciliations_organization_id_fkey"     FOREIGN KEY ("organization_id") REFERENCES "organizations"("id") ON DELETE CASCADE ON UPDATE CASCADE;  -- Alteraâ”œÂºâ”œÃes em tabelas existentes ALTER TABLE "financial_entries" ADD COLUMN IF NOT EXISTS "account_id" TEXT; ALTER TABLE "financial_entries" ADD COLUMN IF NOT EXISTS "cost_center_id" TEXT; ALTER TABLE "financial_entries" ADD COLUMN IF NOT EXISTS "document_type" TEXT; ALTER TABLE "financial_entries" ADD COLUMN IF NOT EXISTS "document_number" TEXT; ALTER TABLE "financial_entries" ADD COLUMN IF NOT EXISTS "amount_paid" DECIMAL(12,2) NOT NULL DEFAULT 0; ALTER TABLE "financial_entries" ADD COLUMN IF NOT EXISTS "issue_date" DATE; ALTER TABLE "financial_entries" ADD COLUMN IF NOT EXISTS "notes" TEXT; ALTER TABLE "financial_entries" ADD COLUMN IF NOT EXISTS "attachment_url" TEXT; ALTER TABLE "financial_entries" ADD COLUMN IF NOT EXISTS "reversed_at" TIMESTAMP(3); ALTER TABLE "financial_entries" ADD COLUMN IF NOT EXISTS "reversed_by_user_id" TEXT; ALTER TABLE "financial_entries" ADD COLUMN IF NOT EXISTS "reversal_reason" TEXT;  CREATE INDEX IF NOT EXISTS "financial_entries_account_id_idx" ON "financial_entries"("account_id"); CREATE INDEX IF NOT EXISTS "financial_entries_cost_center_id_idx" ON "financial_entries"("cost_center_id");  ALTER TABLE "financial_entries" ADD CONSTRAINT "financial_entries_account_id_fkey"     FOREIGN KEY ("account_id") REFERENCES "financial_accounts"("id") ON DELETE SET NULL ON UPDATE CASCADE; ALTER TABLE "financial_entries" ADD CONSTRAINT "financial_entries_cost_center_id_fkey"     FOREIGN KEY ("cost_center_id") REFERENCES "cost_centers"("id") ON DELETE SET NULL ON UPDATE CASCADE;  ALTER TABLE "financial_payment_splits" ADD COLUMN IF NOT EXISTS "account_id" TEXT; CREATE INDEX IF NOT EXISTS "financial_payment_splits_account_id_idx" ON "financial_payment_splits"("account_id"); ALTER TABLE "financial_payment_splits" ADD CONSTRAINT "financial_payment_splits_account_id_fkey"     FOREIGN KEY ("account_id") REFERENCES "financial_accounts"("id") ON DELETE SET NULL ON UPDATE CASCADE;  ALTER TABLE "cash_register_sessions" ADD COLUMN IF NOT EXISTS "account_id" TEXT; ALTER TABLE "cash_register_sessions" ADD CONSTRAINT "cash_register_sessions_account_id_fkey"     FOREIGN KEY ("account_id") REFERENCES "financial_accounts"("id") ON DELETE SET NULL ON UPDATE CASCADE;  ALTER TABLE "products" ADD COLUMN IF NOT EXISTS "internal_code" TEXT; ALTER TABLE "products" ADD COLUMN IF NOT EXISTS "barcode" TEXT; ALTER TABLE "products" ADD COLUMN IF NOT EXISTS "subcategory" TEXT; ALTER TABLE "products" ADD COLUMN IF NOT EXISTS "cest" TEXT; ALTER TABLE "products" ADD COLUMN IF NOT EXISTS "unit" TEXT DEFAULT 'UN'; ALTER TABLE "products" ADD COLUMN IF NOT EXISTS "weight" DECIMAL(10,3); ALTER TABLE "products" ADD COLUMN IF NOT EXISTS "max_stock" INTEGER; ALTER TABLE "products" ADD COLUMN IF NOT EXISTS "markup" DECIMAL(5,2); ALTER TABLE "products" ADD COLUMN IF NOT EXISTS "image_url" TEXT; ALTER TABLE "products" ADD COLUMN IF NOT EXISTS "notes" TEXT;  ALTER TABLE "purchase_order_items" ADD COLUMN IF NOT EXISTS "ipi" DECIMAL(12,2) NOT NULL DEFAULT 0; ALTER TABLE "purchase_order_items" ADD COLUMN IF NOT EXISTS "icms" DECIMAL(12,2) NOT NULL DEFAULT 0;  -- Backfill: Caixa Principal por organizaâ”œÂºâ”œÃºo INSERT INTO "financial_accounts" (     "id", "organization_id", "name", "type", "opening_balance", "current_balance",     "status", "color", "allows_movement", "is_primary", "created_at", "updated_at" ) SELECT     'caixa_' || o."id",     o."id",     'Caixa Principal',     'CAIXA'::"FinancialAccountType",     0,     0,     'ACTIVE'::"FinancialAccountStatus",     '#16A34A',     true,     true,     NOW(),     NOW() FROM "organizations" o WHERE NOT EXISTS (     SELECT 1 FROM "financial_accounts" fa     WHERE fa."organization_id" = o."id" AND fa."is_primary" = true );  -- Backfill: centros de custo padrâ”œÃºo INSERT INTO "cost_centers" ("id", "organization_id", "name", "is_system", "is_active", "created_at") SELECT     'cc_' || o."id" || '_' || REPLACE(LOWER(cc.name), ' ', '_'),     o."id",     cc.name,     true,     true,     NOW() FROM "organizations" o CROSS JOIN (VALUES     ('Oficina'), ('Administraâ”œÂºâ”œÃºo'), ('Estoque'), ('Recepâ”œÂºâ”œÃºo'),     ('Marketing'), ('Financeiro'), ('Outros') ) AS cc(name) WHERE NOT EXISTS (     SELECT 1 FROM "cost_centers" c     WHERE c."organization_id" = o."id" AND c."name" = cc.name );  -- Vincular sessâ”œÃes de caixa â”œÃ¡ conta principal UPDATE "cash_register_sessions" crs SET "account_id" = fa."id" FROM "financial_accounts" fa WHERE crs."organization_id" = fa."organization_id"   AND fa."is_primary" = true   AND crs."account_id" IS NULL;  -- Vincular lanâ”œÂºamentos pagos â”œÃ¡ conta principal (legado) UPDATE "financial_entries" fe SET "account_id" = fa."id" FROM "financial_accounts" fa WHERE fe."organization_id" = fa."organization_id"   AND fa."is_primary" = true   AND fe."status" = 'PAID'   AND fe."account_id" IS NULL;  -- Sincronizar amount_paid com amount_received para registros jâ”œÃ­ pagos UPDATE "financial_entries" SET "amount_paid" = COALESCE("amount_received", "amount") WHERE "status" = 'PAID' AND "amount_paid" = 0;

